-- Enable UUID extension if not present
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================================
-- Table: countries (21 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS countries (
  id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),
  name varchar NOT NULL,
  code varchar NOT NULL,
  code_2 varchar NOT NULL,
  flag_emoji varchar,
  continent varchar DEFAULT 'Europe',
  created_at timestamptz DEFAULT now()
);


-- ============================================================
-- Table: leagues (18 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS leagues (
  id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),
  country_id uuid REFERENCES countries(id),
  name varchar NOT NULL,
  short_name varchar,
  division integer NOT NULL DEFAULT 1,
  league_type varchar DEFAULT 'domestic',
  logo_url text,
  is_active boolean DEFAULT true,
  created_at timestamptz DEFAULT now(),
  country text
);


-- ============================================================
-- Table: clubs (139 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS clubs (
  id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),
  name varchar NOT NULL,
  short_name varchar,
  country_id uuid REFERENCES countries(id),
  current_league_id uuid REFERENCES leagues(id),
  founded_year integer,
  city varchar,
  nickname varchar,
  primary_color varchar,
  secondary_color varchar,
  crest_url text,
  wikipedia_url text,
  official_website text,
  is_active boolean DEFAULT true,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);


-- ============================================================
-- Table: stadiums (133 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS stadiums (
  id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),
  name varchar NOT NULL,
  club_id uuid REFERENCES clubs(id),
  country_id uuid REFERENCES countries(id),
  city varchar,
  address text,
  latitude numeric NOT NULL,
  longitude numeric NOT NULL,
  capacity integer,
  built_year integer,
  renovated_year integer,
  architect varchar,
  surface varchar DEFAULT 'grass',
  former_names text[],
  notable_events text,
  record_attendance integer,
  record_attendance_match text,
  record_attendance_date date,
  thumbnail_url text,
  is_active boolean DEFAULT true,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now(),
  image_url text
);


-- ============================================================
-- Table: stadium_visits (21 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS stadium_visits (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  stadium_id uuid REFERENCES stadiums(id),
  first_visit_date date,
  last_visit_date date,
  visit_count integer,
  notes text,
  is_wishlist boolean DEFAULT false,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);


-- ============================================================
-- Table: bram_custom_stadiums (1 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS bram_custom_stadiums (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name varchar,
  club_name varchar,
  city varchar,
  country varchar,
  latitude numeric,
  longitude numeric,
  capacity integer,
  built_year integer,
  notes text,
  created_at timestamptz DEFAULT now(),
  primary_color text
);


